"use client";

import { useEffect, useState } from "react";
import { Container } from "@/components/layout/Container";
import { Header } from "@/components/layout/Header";
import { AuditRecord } from "@/lib/audit/types";
import Link from "next/link";
import { ArrowRight, Clock, FileText, TrendingDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/Skeleton";

export default function HistoryPage() {
  const [history, setHistory] = useState<AuditRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [hasMounted, setHasMounted] = useState(false);

  useEffect(() => {
    setHasMounted(true);
    const historyJson = localStorage.getItem("ledger_audit_history");
    if (historyJson) {
      try {
        setHistory(JSON.parse(historyJson));
      } catch (e) {
        console.error("Failed to parse audit history");
      }
    }
    setLoading(false);
  }, []);

  const isLoading = !hasMounted || loading;

  return (
    <div className="min-h-screen bg-background text-foreground flex flex-col font-sans">
      <Header />

      <main className="flex-1 py-20 bg-grid-pattern bg-[size:40px_40px]">
        <Container>
          <div className="max-w-5xl mx-auto">
            <div className="mb-12 space-y-4">
              <div className="inline-flex items-center border border-border bg-background px-3 py-1 text-xs font-mono font-bold uppercase tracking-widest text-foreground shadow-sm">
                <span className="flex h-1.5 w-1.5 bg-primary mr-2"></span>
                Archival Ledger
              </div>
              <h1 className="text-5xl font-semibold tracking-tighter">Audit History</h1>
              <p className="text-xl text-muted-foreground max-w-2xl">
                A persistent record of all infrastructure reconciliations and optimization reports generated by LedgerAI.
              </p>
            </div>

            {isLoading ? (
              <div className="border border-border bg-card shadow-sm divide-y divide-border overflow-hidden">
                {Array.from({ length: 5 }).map((_, i) => (
                  <div key={i} className="grid grid-cols-12 gap-4 px-8 py-8 items-center">
                    <Skeleton className="col-span-3 h-8" />
                    <Skeleton className="col-span-2 h-6" />
                    <Skeleton className="col-span-2 h-4" />
                    <Skeleton className="col-span-3 h-6" />
                    <Skeleton className="col-span-2 h-6" />
                  </div>
                ))}
              </div>
            ) : history.length === 0 ? (
              <div className="py-20 border border-border bg-card p-12 text-center space-y-8">
                <div className="size-16 bg-muted mx-auto flex items-center justify-center">
                  <FileText className="h-8 w-8 text-muted-foreground" />
                </div>
                <div className="space-y-2">
                  <h2 className="text-2xl font-semibold tracking-tight">No historical records found</h2>
                  <p className="text-muted-foreground">Initialize your first audit to begin tracking your infrastructure spend.</p>
                </div>
                <Link href="/onboarding">
                  <Button size="lg" className="h-14 px-8 uppercase tracking-widest font-bold shadow-none">
                    Initialize Audit <ArrowRight className="ml-2 h-4 w-4" />
                  </Button>
                </Link>
              </div>
            ) : (
              <div className="border border-border bg-card shadow-sm divide-y divide-border overflow-hidden">
                <div className="grid grid-cols-12 gap-4 px-8 py-4 bg-muted/30 text-xs font-mono font-bold uppercase tracking-widest text-muted-foreground border-b border-border">
                  <div className="col-span-3">Timestamp</div>
                  <div className="col-span-2">Audit ID</div>
                  <div className="col-span-2">Score</div>
                  <div className="col-span-3 text-right">Savings (Annual)</div>
                  <div className="col-span-2 text-right">Status</div>
                </div>

                {history.map((record) => (
                  <Link 
                    key={record.id} 
                    href={`/dashboard?id=${record.id}`}
                    className="grid grid-cols-12 gap-4 px-8 py-8 items-center hover:bg-muted/50 transition-colors group"
                  >
                    <div className="col-span-3 flex items-center gap-3">
                      <Clock className="h-4 w-4 text-muted-foreground group-hover:text-primary transition-colors" />
                      <div className="flex flex-col">
                        <span className="font-mono text-sm">
                          {new Date(record.timestamp).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                        </span>
                        <span className="text-[10px] text-muted-foreground font-mono">
                          {new Date(record.timestamp).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false })}
                        </span>
                      </div>
                    </div>
                    <div className="col-span-2 font-mono font-bold text-foreground">
                      {record.id}
                    </div>
                    <div className="col-span-2">
                      <div className="flex items-center gap-2">
                        <div className="h-1.5 flex-1 bg-muted overflow-hidden">
                          <div 
                            className="h-full bg-primary transition-all duration-1000" 
                            style={{ width: `${record.result.optScore}%` }}
                          />
                        </div>
                        <span className="font-mono text-sm font-bold">{record.result.optScore}</span>
                      </div>
                    </div>
                    <div className="col-span-3 text-right">
                      <div className="flex flex-col items-end">
                        <span className="font-mono font-bold text-primary">
                          {record.result.annualSavings.toLocaleString("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 })}
                        </span>
                        <span className="text-[10px] text-muted-foreground font-mono flex items-center gap-1 uppercase tracking-tighter">
                          <TrendingDown className="h-2 w-2" /> {record.result.leakagePercent}% Leakage
                        </span>
                      </div>
                    </div>
                    <div className="col-span-2 text-right">
                      <span className="inline-flex items-center border border-primary/20 bg-primary/10 px-2 py-0.5 text-[10px] font-mono font-bold text-primary uppercase tracking-widest">
                        Archived
                      </span>
                    </div>
                  </Link>
                ))}
              </div>
            )}
          </div>
        </Container>
      </main>
    </div>
  );
}

import { Metadata } from "next";
import { createClient } from "@/utils/supabase/server";
import { cookies } from "next/headers";
import { Container } from "@/components/layout/Container";
import { Header } from "@/components/layout/Header";
import Link from "next/link";
import { ArrowRight } from "lucide-react";

interface PageProps {
  params: Promise<{ id: string }>;
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const { id } = await params;
  return {
    title: `Audit ${id} Results — LedgerAI`,
    description: `AI infrastructure spend audit results. See the findings from audit ${id}.`,
    openGraph: {
      title: `AI Spend Audit ${id} — LedgerAI`,
      description: "This startup audited their AI tool spend and found potential savings. See the full breakdown.",
      type: "website",
    },
    twitter: {
      card: "summary_large_image",
      title: `AI Spend Audit ${id} — LedgerAI`,
      description: "This startup audited their AI tool spend and found potential savings.",
    },
  };
}

export default async function SharePage({ params }: PageProps) {
  const { id } = await params;
  const cookieStore = await cookies();
  const supabase = createClient(cookieStore);

  let auditData: any = null;
  let auditResult: any = null;

  try {
    const { data, error } = await supabase
      .from("audits")
      .select("data, result, created_at")
      .eq("id", id)
      .single();

    if (!error && data) {
      auditData = data.data;
      auditResult = data.result;
    }
  } catch (e) {
    console.error("Share page fetch error:", e);
  }

  if (!auditData || !auditResult) {
    return (
      <div className="min-h-screen bg-background text-foreground flex flex-col">
        <Header />
        <main className="flex-1 flex items-center justify-center">
          <Container>
            <div className="max-w-xl mx-auto text-center space-y-6 py-32">
              <h1 className="text-4xl font-semibold tracking-tighter">Audit not found</h1>
              <p className="text-muted-foreground">This audit report may have expired or been removed.</p>
              <Link href="/onboarding" className="inline-flex items-center gap-2 bg-foreground text-background px-8 py-4 font-bold uppercase tracking-widest text-sm hover:bg-foreground/90 transition-colors">
                Run Your Own Audit <ArrowRight className="h-4 w-4" />
              </Link>
            </div>
          </Container>
        </main>
      </div>
    );
  }

  const tools = auditResult.toolResults || [];
  const annualSavings = auditResult.annualSavings || 0;
  const monthlySavings = auditResult.monthlySavings || 0;
  const leakagePercent = auditResult.leakagePercent || 0;

  return (
    <div className="min-h-screen bg-background text-foreground flex flex-col">
      <Header />
      <main className="flex-1">

        {/* Hero */}
        <section className="bg-foreground text-background py-20 border-b border-border">
          <Container>
            <div className="max-w-4xl">
              <div className="inline-flex items-center border border-background/20 px-3 py-1 text-xs font-mono font-bold uppercase tracking-widest text-background/70 mb-8">
                <span className="flex h-1.5 w-1.5 bg-primary mr-2"></span>
                Shared Audit Report · {id}
              </div>
              <h1 className="text-5xl font-semibold tracking-tighter mb-4">
                {annualSavings.toLocaleString("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 })}
                <span className="text-2xl font-normal text-background/50 ml-3">potential annual savings</span>
              </h1>
              <p className="text-xl text-background/60 max-w-2xl">
                This AI spend audit identified {leakagePercent}% leakage across {tools.length || auditData.vendors?.length || 0} tools — 
                {monthlySavings.toLocaleString("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 })}/mo recoverable.
              </p>
            </div>
          </Container>
        </section>

        {/* Tool breakdown (sanitized — no email/company) */}
        {tools.length > 0 && (
          <section className="py-16 border-b border-border bg-background">
            <Container>
              <h2 className="text-sm font-mono font-bold tracking-[0.2em] uppercase text-muted-foreground mb-8">
                Tool Breakdown
              </h2>
              <div className="bg-card border border-border shadow-sm overflow-x-auto">
                <table className="w-full text-sm text-left">
                  <thead className="text-xs text-muted-foreground bg-muted/30 border-b border-border uppercase tracking-wider">
                    <tr>
                      <th className="px-8 py-5 font-semibold">Tool</th>
                      <th className="px-8 py-5 font-semibold">Plan</th>
                      <th className="px-8 py-5 font-semibold text-right">Gross Spend</th>
                      <th className="px-8 py-5 font-semibold text-right">Savings Found</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-border font-mono text-sm">
                    {tools.map((t: any, i: number) => (
                      <tr key={i} className="hover:bg-muted/50 transition-colors">
                        <td className="px-8 py-6 font-bold text-foreground font-sans">{t.name}</td>
                        <td className="px-8 py-6 text-muted-foreground">{t.plan}</td>
                        <td className="px-8 py-6 text-right">
                          {t.grossSpend.toLocaleString("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 })}
                        </td>
                        <td className="px-8 py-6 text-right font-bold text-primary">
                          {t.savings > 0
                            ? `${t.savings.toLocaleString("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 })}/mo`
                            : <span className="text-muted-foreground font-normal">Optimal</span>}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </Container>
          </section>
        )}

        {/* CTA */}
        <section className="py-24 bg-muted/20">
          <Container>
            <div className="max-w-2xl mx-auto text-center space-y-8">
              <h2 className="text-4xl font-semibold tracking-tighter">
                Run your own free audit.
              </h2>
              <p className="text-xl text-muted-foreground">
                Takes 2 minutes. No signup required to see results.
              </p>
              <Link href="/onboarding" className="inline-flex items-center gap-2 bg-foreground text-background px-10 py-5 font-bold uppercase tracking-widest text-sm hover:bg-foreground/90 transition-colors">
                Start Free Audit <ArrowRight className="h-4 w-4" />
              </Link>
            </div>
          </Container>
        </section>

      </main>
    </div>
  );
}

